#include <stdio.h>

// Recursive function to find GCD of two numbers
int gcd(int a, int b) {
    // Base case: if second number is 0, GCD is the first number
    if (b == 0)
        return a;
    // Recursive case: call gcd with b and the remainder of a divided by b
    return gcd(b, a % b);
}

int main() {
    int num1, num2;

